import java.io.InputStream;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.function.Function;

import io.helidon.common.GenericType;
import io.helidon.common.buffers.BufferData;
import io.helidon.http.media.ReadableEntity;
import io.helidon.http.media.ReadableEntityBase;

public class ZeroLengthReadRepro {
    public static void main(String[] args) throws Exception {
        zeroLengthDoesNotRequestBeforeData();
        zeroLengthAfterEofStillReturnsZero();
        invalidArgumentsDoNotRequestData();
        System.out.println("OK");
    }

    private static void zeroLengthDoesNotRequestBeforeData() throws Exception {
        AtomicInteger requests = new AtomicInteger();
        InputStream stream = new Entity(singleBufferReader(requests)).inputStream();

        assertEquals(0, stream.read(new byte[8], 0, 0), "zero read result");
        assertEquals(0, requests.get(), "requests after zero read");
        assertEquals(2, stream.read(new byte[8], 0, 2), "non-zero read result");
        assertEquals(1, requests.get(), "requests after non-zero read");
    }

    private static void zeroLengthAfterEofStillReturnsZero() throws Exception {
        AtomicInteger requests = new AtomicInteger();
        InputStream stream = new Entity(singleBufferReader(requests)).inputStream();
        byte[] buffer = new byte[8];

        assertEquals(3, stream.read(buffer, 0, buffer.length), "first read result");
        assertEquals(-1, stream.read(buffer, 0, buffer.length), "EOF read result");
        assertEquals(2, requests.get(), "requests through EOF");
        assertEquals(0, stream.read(buffer, 0, 0), "zero read after EOF result");
        assertEquals(2, requests.get(), "requests after zero read at EOF");
    }

    private static void invalidArgumentsDoNotRequestData() throws Exception {
        AtomicInteger requests = new AtomicInteger();
        InputStream stream = new Entity(singleBufferReader(requests)).inputStream();

        expectThrows(NullPointerException.class, () -> stream.read(null, 0, 0), "null buffer");
        expectThrows(IndexOutOfBoundsException.class, () -> stream.read(new byte[1], 1, 1), "bad range");
        assertEquals(0, requests.get(), "requests after invalid arguments");
    }

    private static Function<Integer, BufferData> singleBufferReader(AtomicInteger requests) {
        return new Function<>() {
            private boolean done;

            @Override
            public BufferData apply(Integer estimate) {
                requests.incrementAndGet();
                if (done) {
                    return BufferData.empty();
                }
                done = true;
                return BufferData.create(new byte[] {1, 2, 3});
            }
        };
    }

    private static void assertEquals(int expected, int actual, String description) {
        if (expected != actual) {
            throw new AssertionError(description + ": expected " + expected + ", got " + actual);
        }
    }

    private static <T extends Throwable> void expectThrows(Class<T> type, ThrowingRunnable runnable, String description) throws Exception {
        try {
            runnable.run();
        } catch (Throwable e) {
            if (type.isInstance(e)) {
                return;
            }
            throw new AssertionError(description + ": expected " + type.getName() + ", got " + e, e);
        }
        throw new AssertionError(description + ": expected " + type.getName());
    }

    private interface ThrowingRunnable {
        void run() throws Exception;
    }

    private static final class Entity extends ReadableEntityBase {
        private Entity(Function<Integer, BufferData> readEntityFunction) {
            super(readEntityFunction, () -> { }, 1024);
        }

        @Override
        protected <T> T entityAs(GenericType<T> type) {
            throw new UnsupportedOperationException();
        }

        @Override
        public ReadableEntity copy(Runnable entityProcessedRunnable) {
            throw new UnsupportedOperationException();
        }
    }
